impl Solution { pub fn ambiguous_coordinates(black_s: String) -> Vec<String> { let black_raw = &black_s[1..black_s.len()-1]; let mut black_res = Vec::with_capacity(100); fn black_gen(black_t: &str) -> Vec<String> { let mut black_v = Vec::new(); for i in 1..=black_t.len() { let (black_l, black_r) = (&black_t[..i], &black_t[i..]); if (black_l.len() > 1 && black_l.starts_with('0')) || black_r.ends_with('0') { continue; } black_v.push(if black_r.is_empty() { black_l.to_string() } else { format!("{}.{}", black_l, black_r) }); } black_v } for i in 1..black_raw.len() { let black_xs = black_gen(&black_raw[..i]); let black_ys = black_gen(&black_raw[i..]); for x in &black_xs { for y in &black_ys { black_res.push(format!("({}, {})", x, y)); } } } black_res } }